mutation K8sCreateWorkerNodePool($payload: K8sCreateWorkerNodePoolReq) {
  K8sCreateWorkerNodePool(K8sCreateWorkerNodePoolReq: $payload) {
    worker_node_pool {
      uuid
      state
      spec {
        name
        droplet_size_slug
        num_nodes
        auto_replace_outdated_nodes
        tags
        auto_scale
        min_nodes
        max_nodes
        __typename
      }
      statuses {
        uuid
        droplet_id
        state
        timestamps {
          created_at {
            nanos
            seconds
            __typename
          }
          updated_at {
            nanos
            seconds
            __typename
          }
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}
